/**
 * Notes Page
 *
 * Main notes interface with 3-column layout:
 * - Left: Folder tree + Notes list
 * - Center: Rich text editor
 * - Right: Note metadata (optional, collapsible)
 */

import React, { useEffect, useState, useRef, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useNotesStore } from '../stores/useNotesStore';
import { useFoldersStore } from '../stores/useFoldersStore';
import { NotesEditor, NotesEditorEmpty } from '../widgets/NotesEditor';
import { ConfirmDialog } from '../components/ConfirmDialog';
import { PromptDialog } from '../components/PromptDialog';
import { useUndoStore } from '../stores/useUndoStore';
import { exportNoteToMarkdown } from '../services/noteExport';
import { exportNoteToPDF } from '../services/notePdfExport';
import { logger } from '../services/logger';
import type { Note } from '../types/notes';

const log = logger.module('Notes');

/**
 * Recursive Folder Tree Node Component
 */
interface FolderTreeNodeProps {
  node: any;
  depth: number;
  activeFolderId: string | null;
  expandedFolderIds: Set<string>;
  onSelect: (id: string) => void;
  onToggleExpanded: (id: string) => void;
  onDelete: (id: string, name: string) => void;
  onRename: (id: string, name: string) => void;
  getFolderNoteCount: (id: string) => number;
}

const FolderTreeNode: React.FC<FolderTreeNodeProps> = ({
  node,
  depth,
  activeFolderId,
  expandedFolderIds,
  onSelect,
  onToggleExpanded,
  onDelete,
  onRename,
  getFolderNoteCount,
}) => {
  const isExpanded = expandedFolderIds.has(node.id);
  const hasChildren = node.children && node.children.length > 0;
  const noteCount = getFolderNoteCount(node.id);

  return (
    <div>
      <div
        className={`group relative rounded-lg transition-colors ${
          activeFolderId === node.id
            ? 'bg-primary-cyan bg-opacity-10'
            : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
        }`}
        style={{ paddingLeft: `${depth * 16}px` }}
      >
        <div className="flex items-center">
          {/* Expand/collapse button */}
          {hasChildren && (
            <button
              onClick={(e) => {
                e.stopPropagation();
                onToggleExpanded(node.id);
              }}
              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-colors"
            >
              <span className="text-sm">{isExpanded ? '▼' : '▶'}</span>
            </button>
          )}
          {!hasChildren && <span className="w-6" />}

          {/* Folder button */}
          <button
            onClick={() => onSelect(node.id)}
            className={`flex-1 text-left px-3 py-2 transition-colors flex items-center gap-2 ${
              activeFolderId === node.id
                ? 'text-primary-cyan font-medium'
                : 'text-text-light-secondary dark:text-text-dark-secondary'
            }`}
          >
            <span>{hasChildren ? (isExpanded ? '📂' : '📁') : '📄'}</span>
            <span>{node.name}</span>
            {noteCount > 0 && (
              <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                ({noteCount})
              </span>
            )}
          </button>

          {/* Action buttons */}
          <div className="absolute right-2 opacity-0 group-hover:opacity-100 flex gap-1 transition-opacity">
            <button

import React, { lazy, Suspense, useEffect } from 'react';

// Lazy load Kanban widget
const Kanban = lazy(() =>
  import('../widgets/Kanban').then((module) => ({ default: module.Kanban }))
);

// Loading fallback
const WidgetLoader = () => (
  <div className="bento-card p-6 h-[600px] animate-pulse">
    <div className="h-full bg-gradient-to-r from-neutral-200 to-neutral-300 dark:from-neutral-800 dark:to-neutral-700 rounded"></div>
  </div>
);

/**
 * Tasks Page - Kanban board
 * Full-featured task management with drag-and-drop
 */
export const Tasks: React.FC = () => {
  useEffect(() => {
    document.title = 'Neuman Brain';
  }, []);

  return (
    <div className="tasks-page">
      <div className="mb-6">
        <h1 className="text-3xl font-bold text-text-light-primary dark:text-text-dark-primary mb-2">
          Task Management
        </h1>
        <p className="text-text-light-secondary dark:text-text-dark-secondary">
          Organize and track your tasks with Kanban board
        </p>
      </div>

      {/* Kanban Widget */}
      <Suspense fallback={<WidgetLoader />}>
        <Kanban />
      </Suspense>
    </div>
  );
};

