     1→import { create } from 'zustand';
     2→import { persist } from 'zustand/middleware';
     3→import type { ThemeState, ThemeMode } from '../types';
     4→
     5→export const useThemeStore = create<ThemeState>()(
     6→  persist(
     7→    (set) => ({
     8→      mode: 'dark',
     9→
    10→      backupPreferences: {
    11→        hasBackupFolder: false,
    12→        backupFolderPath: null,
    13→        autoSaveEnabled: false,
    14→        saveInterval: 30000, // 30 seconds
    15→        versionsToKeep: 7,
    16→        customFileName: 'Neuman.Brain',
    17→        reminderPreference: 'every-session',
    18→        nextReminderDate: null,
    19→      },
    20→
    21→      toggleTheme: () =>
    22→        set((state) => {
    23→          const newMode: ThemeMode = state.mode === 'dark' ? 'light' : 'dark';
    24→
    25→          // Update document class
    26→          if (newMode === 'dark') {
    27→            document.documentElement.classList.add('dark');
    28→          } else {
    29→            document.documentElement.classList.remove('dark');
    30→          }
    31→
    32→          return { mode: newMode };
    33→        }),
    34→
    35→      updateBackupPreferences: (preferences) =>
    36→        set((state) => ({
    37→          backupPreferences: {
    38→            ...state.backupPreferences,
    39→            ...preferences,
    40→          },
    41→        })),
    42→    }),
    43→    {
    44→      name: 'theme-storage',
